namespace sv_6bb8c8c5a53345878bb2afa21b4305ee;

public record TaskItem(int Id, string Title, string Assignee, string Priority, DateTime DueDate, string Status);

public interface ITaskService
{
    Task<List<TaskItem>> GetAllTasksAsync();
    Task<TaskItem> CreateTaskAsync(string title, string assignee, string priority, DateTime dueDate);
    Task UpdateTaskStatusAsync(int taskId, string newStatus);
}

namespace sv_6bb8c8c5a53345878bb2afa21b4305ee;

/// <summary>
/// In-memory stub implementation for development/demo purposes.
/// Replace with a real data-backed implementation.
/// </summary>
public class InMemoryTaskService : ITaskService
{
    private readonly List<TaskItem> _tasks = new()
    {
        new(1, "Design mockups", "Alice", "High", DateTime.Today.AddDays(2), "To Do"),
        new(2, "Set up CI pipeline", "Bob", "Medium", DateTime.Today.AddDays(-1), "In Progress"),
        new(3, "Write unit tests", "Carol", "Low", DateTime.Today.AddDays(5), "Done"),
    };
    private int _nextId = 4;

    public Task<List<TaskItem>> GetAllTasksAsync()
        => Task.FromResult(_tasks.ToList());

    public Task<TaskItem> CreateTaskAsync(string title, string assignee, string priority, DateTime dueDate)
    {
        var task = new TaskItem(_nextId++, title, assignee, priority, dueDate, "To Do");
        _tasks.Add(task);
        return Task.FromResult(task);
    }

    public Task UpdateTaskStatusAsync(int taskId, string newStatus)
    {
        var index = _tasks.FindIndex(t => t.Id == taskId);
        if (index >= 0)
        {
            _tasks[index] = _tasks[index] with { Status = newStatus };
        }
        return Task.CompletedTask;
    }
}

